function ctoServiceNameFor(id = '') {
  const names = {
    openai: 'OpenAI',
    heygen: 'HeyGen',
    'google-workspace': 'Google Workspace',
    gmail: 'Gmail',
    'google-drive': 'Google Drive',
    'google-custom-search': 'Google Custom Search',
    descript: 'Descript',
    'captions-ai': 'Captions AI',
    canva: 'Canva',
    figma: 'Figma',
    linkedin: 'LinkedIn',
    instagram: 'Instagram',
    facebook: 'Facebook',
    youtube: 'YouTube',
    metricool: 'Metricool',
    buffer: 'Buffer',
    supabase: 'Supabase',
    whatsapp: 'WhatsApp',
    slack: 'Slack',
    resend: 'Resend',
    vercel: 'Vercel',
    cloudflare: 'Cloudflare',
    n8n: 'n8n',
    forex: 'Forex Feed',
    news: 'News Feed',
    trademap: 'TradeMap',
    'un-comtrade': 'UN Comtrade',
    kompass: 'Kompass',
    tradeatlas: 'TradeAtlas',
    apeda: 'APEDA',
    'spice-board': 'Spice Board'
  };
  return names[id] || id.replace(/-/g, ' ').replace(/\b\w/g, (letter) => letter.toUpperCase());
}

